// Example: Express + PostgreSQL on Railway
// 1. Create new project on Railway
// 2. Add PostgreSQL service (one click)
// 3. Deploy Express app from GitHub
// 4. DATABASE_URL automatically injected

import express from 'express';
import pg from 'pg';

const app = express();
const pool = new pg.Pool({
  connectionString: process.env.DATABASE_URL,
  ssl: { rejectUnauthorized: false }
});

app.get('/api/users', async (req, res) => {
  const result = await pool.query('SELECT * FROM users');
  res.json(result.rows);
});

app.listen(process.env.PORT || 3000);

// 1. Install Supabase client
// npm install @supabase/supabase-js

// 2. Create Supabase client (lib/supabase.ts)
import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

export const supabase = createClient(supabaseUrl, supabaseKey);

// 3. Create a table in Supabase Dashboard
// Table: posts
// Columns: id (uuid), title (text), content (text), created_at (timestamp)

// 4. Fetch data with auto-generated API
import { supabase } from '@/lib/supabase';

export async function getPosts() {
  const { data, error } = await supabase
    .from('posts')
    .select('*')
    .order('created_at', { ascending: false });

  if (error) throw error;
  return data;
}

// 5. Insert data
export async function createPost(title: string, content: string) {
  const { data, error } = await supabase
    .from('posts')
    .insert({ title, content })
    .select()
    .single();

  if (error) throw error;
  return data;
}

// 6. Real-time subscription
supabase
  .channel('posts')
  .on('postgres_changes', 
    { event: '*', schema: 'public', table: 'posts' },
    (payload) => console.log('Change detected:', payload)
  )
  .subscribe();

// 7. Authentication
